      expect(response.body).to eq({ 'name' => 'Item', 'sku' => 'ABC1234' })
    end
  end

  describe 'POST /items/' do
    it 'Tests UUID field with invalid UUID format' do
      response = client.post('/items/',
        json: { 'item_id' => 'not-a-valid-uuid', 'name' => 'Item' },
        headers: { 'Content-Type' => 'application/json' }
      )
      expect(response.status).to eq(422)
      expect(response.body).to eq({ 'detail' => '1 validation error in request', 'errors' => [{ 'input' => 'not-a-valid-uuid', 'loc' => ['body', 'item_id'], 'msg' => 'Input should be a valid UUID', 'type' => 'uuid_parsing' }], 'status' => 422, 'title' => 'Request Validation Failed', 'type' => 'https://spikard.dev/errors/validation-error' })
    end
  end

  describe 'POST /items/' do
    it 'Tests UUID field with valid UUID format' do
      response = client.post('/items/',
        json: { 'item_id' => 'c892496f-b1fd-4b91-bdb8-b46f92df1716', 'name' => 'Item' },
        headers: { 'Content-Type' => 'application/json' }
      )
      expect(response.status).to eq(200)
      expect(response.body).to eq({ 'item_id' => 'c892496f-b1fd-4b91-bdb8-b46f92df1716', 'name' => 'Item' })
    end
  end
